from collections import deque
class Solution:
    def validPath(self, n, edges, source, destination):
        if source == destination:
            return True
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        seen = [False] * n
        seen[source] = True
        q = deque([source])
        while q:
            x = q.popleft()
            for y in adj[x]:
                if not seen[y]:
                    if y == destination:
                        return True
                    seen[y] = True
                    q.append(y)
        return False

